cd /home/user/workspace/dst && mkdir -p src/main/java/com/example/hello src/main/resources && cat > pom.xml <<'EOF'
<project xmlns="http://maven.apache.org/POM/4.0.0" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
         xsi:schemaLocation="http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd">
    <modelVersion>4.0.0</modelVersion>

    <groupId>com.example</groupId>
    <artifactId>hello-world-api</artifactId>
    <version>1.0.0</version>
    <packaging>jar</packaging>

    <parent>
        <groupId>org.springframework.boot</groupId>
        <artifactId>spring-boot-starter-parent</artifactId>
        <version>3.3.2</version>
        <relativePath/>
    </parent>

    <properties>
        <java.version>17</java.version>
    </properties>

    <dependencies>
        <dependency>
            <groupId>org.springframework.boot</groupId>
            <artifactId>spring-boot-starter-web</artifactId>
        </dependency>
    </dependencies>

    <build>
        <plugins>
            <plugin>
                <groupId>org.springframework.boot</groupId>
                <artifactId>spring-boot-maven-plugin</artifactId>
            </plugin>
        </plugins>
    </build>
</project>
EOF

cat > src/main/java/com/example/hello/HelloWorldApiApplication.java <<'EOF'
package com.example.hello;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class HelloWorldApiApplication {
    public static void main(String[] args) {
        SpringApplication.run(HelloWorldApiApplication.class, args);
    }
}
EOF

cat > src/main/java/com/example/hello/HelloController.java <<'EOF'
package com.example.hello;

import java.util.HashMap;
import java.util.Map;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class HelloController {

    @GetMapping("/")
    public Map<String, String> hello(@RequestParam(name = "name", defaultValue = "") String name) {
        String resolved = name.trim().isEmpty() ? "World" : name.trim();
        Map<String, String> response = new HashMap<>();
        response.put("message", "Hello " + resolved + "!");
        return response;
    }
}
EOF

cat > src/main/resources/application.properties <<'EOF'
server.port=${SERVER_PORT:3000}
server.address=0.0.0.0
EOF
